// Helper Functions
export function getCityBySlug(slug: string): City | undefined {
  return nrwCities.find(city => city.slug === slug);
}

export function getAllCitySlugs(): string[] {
  return nrwCities.map(city => city.slug);
}

export function getCitiesByDistrict(district: string): City[] {
  return nrwCities.filter(city => city.district === district);
}

export function searchCities(query: string): City[] {
  const lowerQuery = query.toLowerCase();
  return nrwCities.filter(city => 
    city.name.toLowerCase().includes(lowerQuery) ||
    city.slug.includes(lowerQuery)
  );
}

